"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { SelectContext } from "./select-context";
import { useSelectState } from "./use-select-state";

interface SelectBaseProps {
  open?: boolean;
  onOpenChange?: (open: boolean) => void;
  defaultOpen?: boolean;
  highlighted?: string | null;
  onHighlight?: (value: string | null) => void;
  disabled?: boolean;
  variant?: "default" | "card";
  /** Sets the width of the Select container. "full" fills the parent. */
  width?: "sm" | "md" | "lg" | "full";
  /** Name attribute for the hidden form input */
  name?: string;
  required?: boolean;
  "aria-invalid"?: boolean;
  children: ReactNode;
  className?: string;
}

interface SelectSingleProps extends SelectBaseProps {
  multiple?: false;
  value?: string;
  onChange?: (value: string) => void;
  defaultValue?: string;
}

interface SelectMultipleProps extends SelectBaseProps {
  multiple: true;
  value?: string[];
  onChange?: (value: string[]) => void;
  defaultValue?: string[];
}

export type SelectProps = SelectSingleProps | SelectMultipleProps;

const widthClasses = {
  sm: "w-48",
  md: "w-64",
  lg: "w-80",
  full: "w-full",
} satisfies Record<NonNullable<SelectBaseProps["width"]>, string>;

export function Select(props: SelectProps) {
  const {
    open,
    onOpenChange,
    defaultOpen,
    value,
    onChange,
    defaultValue,
    highlighted,
    onHighlight,
    multiple,
    disabled = false,
    variant = "default",
    width,
    name,
    required,
    "aria-invalid": ariaInvalid,
    children,
    className,
  } = props;

  const { contextValue, wrapperRef } = useSelectState({
    open,
    onOpenChange,
    defaultOpen,
    value,
    onChange,
    defaultValue,
    highlighted,
    onHighlight,
    multiple,
    disabled,
    variant,
    ariaInvalid,
    required,
  });

  return (
    <SelectContext value={contextValue}>
      <div
        ref={wrapperRef}
        className={cn(
          "relative",
          width && widthClasses[width],
          variant === "card" && "border border-foreground bg-background shadow-[8px_8px_0px_0px_color-mix(in_srgb,var(--border)_50%,transparent)]",
          className
        )}
      >
        {children}
        {name && (
          Array.isArray(contextValue.value)
            ? (
                <>
                  <select
                    name={name}
                    multiple
                    value={contextValue.value}
                    disabled={disabled}
                    tabIndex={-1}
                    aria-hidden="true"
                    className="sr-only"
                    onChange={() => {}}
                  >
                    {contextValue.value.map((v) => (
                      <option key={v} value={v}>{v}</option>
                    ))}
                  </select>
                  {required && (
                    <input
                      type="checkbox"
                      required
                      checked={contextValue.value.length > 0}
                      disabled={disabled}
                      tabIndex={-1}
                      aria-hidden="true"
                      readOnly
                      className="sr-only"
                    />
                  )}
                </>
              )
            : (
                <select
                  name={name}
                  value={contextValue.value}
                  required={required}
                  disabled={disabled}
                  tabIndex={-1}
                  aria-hidden="true"
                  className="sr-only"
                  onChange={() => {}}
                >
                  <option value="" />
                  {contextValue.value && <option value={contextValue.value}>{contextValue.value}</option>}
                </select>
              )
        )}
      </div>
    </SelectContext>
  );
}


"use client";

import { createContext, useContext, type RefObject } from "react";

export interface SelectOptionMetadata {
  label: string;
  disabled: boolean;
}

export interface SelectContextValue {
  open: boolean;
  disabled: boolean;
  onOpenChange: (open: boolean) => void;
  value: string | string[];
  multiple: boolean;
  searchQuery: string;
  onSearchChange: (query: string) => void;
  highlighted: string | null;
  onHighlight: (value: string | null) => void;
  selectItem: (value: string) => void;
  labelsRef: RefObject<Map<string, SelectOptionMetadata>>;
  registerOption: (value: string, metadata: SelectOptionMetadata) => () => void;
  isOptionDisabled: (value: string) => boolean;
  triggerRef: RefObject<HTMLButtonElement | null>;
  searchInputRef: RefObject<HTMLInputElement | null>;
  hasSearch: boolean;
  setHasSearch: (hasSearch: boolean) => void;
  variant: "default" | "card";
  listboxId: string;
  triggerId: string;
  ariaInvalid: boolean | undefined;
}

export const SelectContext = createContext<SelectContextValue | undefined>(
  undefined
);

export function useSelectContext(source?: string): SelectContextValue {
  const context = useContext(SelectContext);
  if (!context) {
    throw new Error(
      `${source ?? "Select compound components"} must be used within a Select`
    );
  }
  return context;
}


export function isValueSelected(value: string | string[], itemValue: string): boolean {
  return Array.isArray(value) ? value.includes(itemValue) : value === itemValue;
}

export function toSelectedArray(value: string | string[], multiple: boolean): string[] {
  if (multiple) return Array.isArray(value) ? value : [];
  return value ? [value as string] : [];
}

export function toOptionId(listboxId: string, value: string): string {
  return `${listboxId}-opt-${value.replace(/\s+/g, "_")}`;
}


"use client";

import type { ComponentPropsWithRef, KeyboardEvent, ReactNode } from "react";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { Chevron } from "../icons/chevron";
import { useSelectContext } from "./select-context";

export interface SelectTriggerProps extends Omit<ComponentPropsWithRef<"button">, "children" | "type" | "disabled"> {
  children: ReactNode;
  /** Custom handle element. Defaults to an animated Chevron. Pass `null` to hide. */
  handle?: ReactNode | null;
  invalid?: boolean;
}

export function SelectTrigger({
  children,
  className,
  handle,
  invalid,
  "aria-errormessage": ariaErrorMessage,
  ref,
  onClick,
  onKeyDown,
  ...props
}: SelectTriggerProps) {
  const { open, disabled, onOpenChange, triggerRef, variant, triggerId, listboxId, ariaInvalid } = useSelectContext("SelectTrigger");

  const handleKeyDown = (e: KeyboardEvent<HTMLButtonElement>) => {
    onKeyDown?.(e);
    if (e.defaultPrevented) return;
    switch (e.key) {
      case "Enter":
      case " ":
        e.preventDefault();
        onOpenChange(!open);
        break;
      case "ArrowDown":
      case "ArrowUp":
        e.preventDefault();
        if (!open) onOpenChange(true);
        break;
    }
  };

  return (
    <button
      {...props}
      ref={composeRefs(triggerRef, ref)}
      id={triggerId}
      type="button"
      disabled={disabled}
      aria-haspopup="listbox"
      aria-expanded={open}
      aria-controls={listboxId}
      aria-invalid={invalid || ariaInvalid || undefined}
      aria-errormessage={ariaErrorMessage}
      onClick={(event) => {
        onClick?.(event);
        if (!event.defaultPrevented) onOpenChange(!open);
      }}
      onKeyDown={handleKeyDown}
      className={cn(
        "flex items-center justify-between w-full px-3 py-2 text-sm font-mono cursor-pointer focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-foreground",
        variant === "card"
          ? "bg-foreground text-accent-foreground border-b border-foreground font-bold text-xs uppercase tracking-wider"
          : "border border-border bg-background text-foreground hover:bg-secondary",
        className
      )}
    >
      {children}
      {handle !== null && (
        handle ?? <Chevron direction="down" open={open} size="sm" className="text-muted-foreground shrink-0" />
      )}
    </button>
  );
}


"use client";

import { useCallback, useLayoutEffect, useRef, type ReactNode, type KeyboardEvent, type Ref, type RefObject } from "react";
import { useNavigation } from "@/hooks/use-navigation";
import { usePresence } from "@/hooks/use-presence";
import { useFloatingPosition, type FloatingSide, type FloatingAlign } from "@/hooks/use-floating-position";
import { composeRefs } from "@/lib/compose-refs";
import { cn } from "@/lib/utils";
import { Portal } from "../shared/portal";
import { useSelectContext } from "./select-context";
import { matchesSearch } from "@/lib/search";
import { toOptionId } from "./select-utils";
import type { SelectOptionMetadata } from "./select-context";

export interface SelectContentProps {
  children: ReactNode;
  className?: string;
  onKeyDown?: (event: KeyboardEvent) => void;
  side?: FloatingSide;
  align?: FloatingAlign;
  sideOffset?: number;
  collisionPadding?: number;
  ref?: Ref<HTMLDivElement>;
}

const NAV_KEYS = new Set(["ArrowUp", "ArrowDown", "Enter", "Home", "End"]);
const TYPEAHEAD_RESET_MS = 500;

export function SelectContent({
  children,
  className,
  onKeyDown,
  side = "bottom",
  align = "start",
  sideOffset = 0,
  collisionPadding = 8,
  ref,
}: SelectContentProps) {
  const {
    open,
    multiple,
    variant,
    value,
    highlighted,
    onHighlight,
    onOpenChange,
    selectItem,
    listboxId,
    triggerId,
    searchInputRef,
    hasSearch,
    triggerRef,
    labelsRef,
    searchQuery,
  } = useSelectContext("SelectContent");
  const containerRef = useRef<HTMLDivElement>(null);
  const isDropdown = variant !== "card";

  const { onKeyDown: navKeyDown } = useNavigation({
    containerRef,
    role: "option",
    wrap: true,
    value: highlighted,
    onValueChange: onHighlight,
    onSelect: selectItem,
    enabled: open,
  });

  const typeaheadBuffer = useRef("");
  const typeaheadTimer = useRef<number>(0);

  function handleTypeahead(key: string): void {
    if (key.length !== 1 || key === " ") return;
    clearTimeout(typeaheadTimer.current);
    typeaheadBuffer.current += key;
    typeaheadTimer.current = window.setTimeout(() => {
      typeaheadBuffer.current = "";
    }, TYPEAHEAD_RESET_MS);

    const query = typeaheadBuffer.current.toLowerCase();
    for (const [itemValue, option] of labelsRef.current) {
      if (!option.disabled && option.label.toLowerCase().startsWith(query)) {
        onHighlight(itemValue);
        break;
      }
    }
  }

  const { present, onAnimationEnd } = usePresence({ open: isDropdown && open, ref: containerRef });
  const { position, contentRef } = useFloatingPosition({
    triggerRef,
    open: isDropdown && present,
    side,
    align,
    sideOffset,
    alignOffset: 0,
    collisionPadding,
    avoidCollisions: true,
  });

  const initHighlight = useCallback(() => {
    if (highlighted) return;
    const selectedValues = Array.isArray(value) ? value : value ? [value] : [];
    if (selectedValues[0] && !labelsRef.current.get(selectedValues[0])?.disabled) {
      onHighlight(selectedValues[0]);
      return;
    }
    for (const [itemValue, option] of labelsRef.current) {
      if (!option.disabled) {
        onHighlight(itemValue);
        return;
      }
    }
  }, [highlighted, labelsRef, onHighlight, value]);

  const triggerWidthRef = useRef<number | undefined>(undefined);

  useLayoutEffect(() => {
    if (!open) return;
    if (isDropdown) {
      triggerWidthRef.current = triggerRef.current?.getBoundingClientRect().width;
    }
    if (!searchInputRef.current) {
      containerRef.current?.focus();
    }
    initHighlight();
  }, [initHighlight, isDropdown, open, searchInputRef, triggerRef]);

  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === "Escape") {
      e.preventDefault();
      onOpenChange(false);
      triggerRef.current?.focus();
      return;
    }

    if (e.key === "Tab") {
      if (highlighted && !multiple) selectItem(highlighted);
      onOpenChange(false);
      return;
    }

    const isTyping = e.target === searchInputRef.current;
    if (isTyping) {
      if (NAV_KEYS.has(e.key)) navKeyDown(e);
    } else {
      navKeyDown(e);
      if (!e.ctrlKey && !e.metaKey && !e.altKey) handleTypeahead(e.key);
    }

    onKeyDown?.(e);
  };

  const listboxProps = {
    id: listboxId,
    role: "listbox" as const,
    tabIndex: -1,
    "aria-multiselectable": multiple || undefined,
    "aria-activedescendant": !hasSearch && highlighted ? toOptionId(listboxId, highlighted) : undefined,
    "aria-labelledby": triggerId,
    onKeyDown: handleKeyDown,
  };

  if (!isDropdown) {
    return (
      <div
        {...listboxProps}
        ref={composeRefs(containerRef, ref)}
        hidden={!open}
        className={cn("w-full overflow-hidden p-1 space-y-0.5 outline-none", className)}
      >
        {children}
        {searchQuery && <MatchCount labelsRef={labelsRef} searchQuery={searchQuery} />}
      </div>
    );
  }

  if (!present) return null;

  return (
    <Portal>
      <div
        {...listboxProps}
        ref={composeRefs(containerRef, contentRef, ref)}
        data-state={open ? "open" : "closed"}
        data-side={position?.side}
        onAnimationEnd={onAnimationEnd}
        className={cn(
          "fixed z-9999 border border-border bg-background shadow-2xl rounded-sm overflow-hidden outline-none",
          "data-[state=open]:animate-slide-in",
          "data-[state=closed]:animate-slide-out",
          className,
        )}
        style={
          position
            ? { top: position.y, left: position.x, width: triggerWidthRef.current }
            : { visibility: "hidden" as const, position: "fixed" as const, top: 0, left: 0 }
        }
      >
        {children}
        {searchQuery && <MatchCount labelsRef={labelsRef} searchQuery={searchQuery} />}
      </div>
    </Portal>
  );
}

function MatchCount({ labelsRef, searchQuery }: { labelsRef: RefObject<Map<string, SelectOptionMetadata>>; searchQuery: string }) {
  let count = 0;
  for (const option of labelsRef.current.values()) {
    if (matchesSearch(option.label, searchQuery)) count++;
  }
  return (
    <div role="status" aria-live="polite" className="sr-only">
      {count} results
    </div>
  );
}


"use client";

import { useLayoutEffect, type ComponentPropsWithRef, type MouseEvent, type ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useSelectContext } from "./select-context";
import { matchesSearch } from "@/lib/search";
import { isValueSelected, toOptionId } from "./select-utils";

const NBSP = "\u00a0";
const BULLET = "\u25cf";
const CHECKMARK = "\u2713";

const selectItemVariants = cva(
  "flex items-center gap-2 px-2 py-1.5 text-sm font-mono cursor-pointer",
  {
    variants: {
      state: {
        default: "text-foreground/60",
        highlighted: "bg-secondary text-foreground",
        selected: "bg-foreground text-background font-medium",
        selectedMulti: "text-foreground",
        selectedMultiHighlighted: "bg-secondary text-foreground",
      },
      variant: {
        default: "",
        card: "",
      },
    },
    compoundVariants: [
      { variant: "card", state: ["default", "selectedMulti"], class: "text-muted-foreground hover:bg-border/30" },
      { variant: "card", state: "highlighted", class: "text-muted-foreground bg-border/30" },
      { variant: "card", state: ["selected", "selectedMultiHighlighted"], class: "bg-muted-foreground text-white font-medium" },
    ],
    defaultVariants: { state: "default", variant: "default" },
  }
);

type ItemState = "default" | "highlighted" | "selected" | "selectedMulti" | "selectedMultiHighlighted";

function getItemState(isSelected: boolean, isHighlighted: boolean, multiple: boolean): ItemState {
  if (!isSelected) return isHighlighted ? "highlighted" : "default";
  if (multiple) return isHighlighted ? "selectedMultiHighlighted" : "selectedMulti";
  return "selected";
}

export type SelectItemIndicator = "auto" | "checkbox" | "radio" | "none";

export interface SelectItemProps extends Omit<ComponentPropsWithRef<"div">, "children" | "onSelect"> {
  value: string;
  children: ReactNode;
  disabled?: boolean;
  /** Controls the selection indicator shown before the item label.
   * - `"auto"` (default): `[x]`/`[ ]` in multiple mode, `✓` in single mode
   * - `"checkbox"`: always shows `[x]`/`[ ]`
   * - `"radio"`: shows `[ • ]`/`[ ]` radio-style
   * - `"none"`: no indicator (text-only)
   */
  indicator?: SelectItemIndicator;
  /** Text for search/typeahead matching. Defaults to children text or value. */
  textValue?: string;
}

function renderIndicator(
  mode: SelectItemIndicator,
  isSelected: boolean,
  isMultiple: boolean,
): string | null {
  if (mode === "none") return null;
  if (mode === "checkbox" || (mode === "auto" && isMultiple)) {
    return isSelected ? "[x]" : "[ ]";
  }
  if (mode === "radio") {
    return isSelected ? `[${NBSP}${BULLET}${NBSP}]` : `[${NBSP}${NBSP}${NBSP}]`;
  }
  return isSelected ? CHECKMARK : null;
}

export function SelectItem({
  value: itemValue,
  children,
  disabled = false,
  indicator = "auto",
  textValue,
  className,
  ref,
  onClick,
  onMouseEnter,
  ...props
}: SelectItemProps) {
  const {
    value,
    multiple,
    highlighted,
    onHighlight,
    searchQuery,
    selectItem,
    variant,
    listboxId,
    registerOption,
  } = useSelectContext("SelectItem");

  const label = textValue ?? (typeof children === "string" ? children : itemValue);

  useLayoutEffect(() => {
    return registerOption(itemValue, { label, disabled });
  }, [disabled, itemValue, label, registerOption]);

  const isSelected = isValueSelected(value, itemValue);

  if (!matchesSearch(label, searchQuery)) return null;

  const isHighlighted = !disabled && highlighted === itemValue;
  const state = getItemState(isSelected, isHighlighted, multiple);
  const indicatorText = renderIndicator(indicator, isSelected, multiple);
  const showIndicatorSlot = indicator !== "none";

  const handleClick = (event: MouseEvent<HTMLDivElement>) => {
    onClick?.(event);
    if (!event.defaultPrevented && !disabled) selectItem(itemValue);
  };

  const handleMouseEnter = (event: MouseEvent<HTMLDivElement>) => {
    onMouseEnter?.(event);
    if (!event.defaultPrevented && !disabled) onHighlight(itemValue);
  };

  return (
    <div
      {...props}
      ref={ref}
      id={toOptionId(listboxId, itemValue)}
      role="option"
      aria-selected={isSelected}
      aria-disabled={disabled || undefined}
      data-value={itemValue}
      data-label={label}
      onClick={handleClick}
      onMouseEnter={handleMouseEnter}
      className={cn(
        selectItemVariants({ state, variant }),
        disabled && "opacity-50 cursor-not-allowed",
        className,
      )}
    >
      {showIndicatorSlot && (
        <span className={cn(
          "font-mono shrink-0 whitespace-nowrap min-w-[3ch]",
          !indicatorText && "invisible"
        )}>
          {indicatorText ?? CHECKMARK}
        </span>
      )}
      <span>{children}</span>
      {variant === "card" && isHighlighted && isSelected && (
        <span aria-hidden="true" className="ml-auto text-[10px] animate-pulse">&lt;</span>
      )}
    </div>
  );
}


"use client";

import { useLayoutEffect } from "react";
import { cn } from "@/lib/utils";
import { useSelectContext } from "./select-context";
import { toOptionId } from "./select-utils";

export interface SelectSearchProps {
  placeholder?: string;
  position?: "top" | "bottom";
  className?: string;
  "aria-label"?: string;
}

function searchBorderClass(variant: string, position: string): string {
  if (variant === "card") return "border-b border-foreground";
  if (position === "top") return "border-b border-border";
  return "border-t border-border";
}

export function SelectSearch({
  placeholder = "Search...",
  position = "bottom",
  className,
  "aria-label": ariaLabel,
}: SelectSearchProps) {
  const { open, searchQuery, onSearchChange, variant, searchInputRef, highlighted, listboxId, setHasSearch } = useSelectContext("SelectSearch");

  useLayoutEffect(() => {
    setHasSearch(true);
    return () => setHasSearch(false);
  }, [setHasSearch]);

  useLayoutEffect(() => {
    if (open) searchInputRef.current?.focus();
  }, [open, searchInputRef]);

  if (!open) return null;

  return (
    <div className={cn("flex items-center gap-2 px-3 py-2", searchBorderClass(variant, position))}>
      <span className="text-foreground/50 text-sm font-mono shrink-0">
        &gt;
      </span>
      <input
        ref={searchInputRef}
        type="text"
        role="combobox"
        aria-label={ariaLabel ?? "Search options"}
        aria-expanded={open}
        aria-controls={listboxId}
        aria-activedescendant={highlighted ? toOptionId(listboxId, highlighted) : undefined}
        aria-autocomplete="list"
        value={searchQuery}
        onChange={(e) => onSearchChange(e.target.value)}
        placeholder={placeholder}
        className={cn(
          "text-sm bg-transparent text-foreground w-full outline-none font-mono placeholder:text-foreground/30",
          className,
        )}
      />
    </div>
  );
}


"use client";

import type { ReactNode, RefObject } from "react";
import { cn } from "@/lib/utils";
import { useSelectContext, type SelectOptionMetadata } from "./select-context";
import { toSelectedArray } from "./select-utils";

export type SelectValueDisplay = "count" | "list" | "truncate";

export interface SelectValueRenderProps {
  selected: string[];
  labels: ReadonlyMap<string, string>;
}

function getLabelMap(options: ReadonlyMap<string, SelectOptionMetadata>): ReadonlyMap<string, string> {
  return new Map(Array.from(options, ([value, option]) => [value, option.label]));
}

export interface SelectValueProps {
  placeholder?: ReactNode;
  display?: SelectValueDisplay;
  truncateAfter?: number;
  className?: string;
  children?: ((props: SelectValueRenderProps) => ReactNode) | ReactNode;
}

function MultiValue({
  selected,
  labelsRef,
  display,
  truncateAfter,
}: {
  selected: string[];
  labelsRef: RefObject<Map<string, SelectOptionMetadata>>;
  display: SelectValueDisplay;
  truncateAfter: number;
}): ReactNode {
  if (selected.length === 1) {
    return <span>{labelsRef.current.get(selected[0]!)?.label ?? selected[0]}</span>;
  }

  const labels = selected.map((v) => labelsRef.current.get(v)?.label ?? v);

  switch (display) {
    case "list":
      return <span>{labels.join(", ")}</span>;

    case "truncate": {
      const visible = labels.slice(0, truncateAfter);
      const overflow = labels.length - truncateAfter;
      return (
        <span>
          {visible.join(", ")}
          {overflow > 0 && ` +${overflow} more`}
        </span>
      );
    }

    case "count":
    default:
      return <span>{selected.length} selected</span>;
  }
}

export function SelectValue({
  placeholder = "Select...",
  display = "count",
  truncateAfter = 2,
  className,
  children,
}: SelectValueProps) {
  const { value, multiple, labelsRef, variant } = useSelectContext("SelectValue");

  const selected = toSelectedArray(value, multiple);

  if (selected.length === 0) {
    return (
      <span className={cn(
        variant === "card" ? "text-accent-foreground/50" : "text-foreground/50",
        className,
      )}>
        {placeholder}
      </span>
    );
  }

  if (typeof children === "function") {
    return <span className={className}>{children({ selected, labels: getLabelMap(labelsRef.current) })}</span>;
  }

  return (
    <span className={className}>
      <MultiValue selected={selected} labelsRef={labelsRef} display={display} truncateAfter={truncateAfter} />
    </span>
  );
}


"use client";

import { cn } from "@/lib/utils";
import { useSelectContext } from "./select-context";
